query:
CREATE TABLE IF NOT EXISTS ad_preview_cache (
  id BIGSERIAL PRIMARY KEY,
  creative_id TEXT NOT NULL,
  ad_format TEXT NOT NULL,
  user_id TEXT NOT NULL,
  iframe_html TEXT NOT NULL,
  cached_at TIMESTAMPTZ NOT NULL DEFAULT NOW(),
  expires_at TIMESTAMPTZ NOT NULL DEFAULT (NOW() + INTERVAL '24 hours'),
  UNIQUE (creative_id, ad_format, user_id)
);

CREATE INDEX IF NOT EXISTS idx_ad_preview_cache_lookup 
  ON ad_preview_cache (creative_id, ad_format, user_id, expires_at);

CREATE INDEX IF NOT EXISTS idx_ad_preview_cache_expires
  ON ad_preview_cache (expires_at);

COMMENT ON TABLE ad_preview_cache IS 'Cache for Meta Ad Preview API iframe HTML — TTL 24 hours';
COMMENT ON COLUMN ad_preview_cache.creative_id IS 'Meta creative ID';
COMMENT ON COLUMN ad_preview_cache.ad_format IS 'Meta ad format (e.g. MOBILE_FEED_STANDARD, INSTAGRAM_STORY)';
COMMENT ON COLUMN ad_preview_cache.user_id IS 'User who fetched the preview';
COMMENT ON COLUMN ad_preview_cache.iframe_html IS 'Raw iframe HTML string from Meta API';
COMMENT ON COLUMN ad_preview_cache.expires_at IS 'Cache expiry timestamp (24h TTL)';

